@startuml
class User {
    int id
    string name
    string github (github地址)
    string sex
    string picture
}

class Login {
    int id
    int username (学生账号就是学号，老师账号是工号)
    string password
    int role (角色)
}

class Experimentcore {
    int id
    int studentId (与学生关联)
    int scoreitemId (与scoreitem关联)
}

class Scoreitem {
    int id
    int complexScore (复杂度得分)
    int completeScore (完成度得分)
    int answerScore (答辩得分)
}

class Experiment {
    int id
    string name (实验名)
    Date date (实验发布时间)
    string github (实验的github地址)
    int courseld (与Course类的id关联)
}

class Course {
    int id
    int courseNum
    string name
    string term
    float credit (学分)
}

class Teacher {
    int teacherNumber (工号)
    string office (办公室)
    string phone
}

class Student {
    int studentNumber (学号)
    string class (班级)
}

class TeacherCourse {
    int id
    int teacherId
    int courseld
}

class StudentCourse {
    int id
    int studentId
    int courseld
}

class Experimentscore {
    int id
    int username (学生账号就是学号，老师账号是工号)
    string password
    int role (角色)
}

class Experimentscore {
    int id
    int studentId (与学生关联)
    int scoreitemId (与scoreitem关联)
}

class User <|-- Teacher
class User <|-- Student

class TeacherCourse {
    "老师选课"类
}

class StudentCourse {
    "学生选课"类
}

class Course {
}

class Teacher {
    1 .. n TeacherCourse
}

class Student {
    1 .. n StudentCourse
}

class Course {
    1 .. n TeacherCourse
    1 .. n StudentCourse
}

class Scoreitem {
    1 .. n Experiment
}

class Experiment {
    1 .. n Scoreitem
}

class Login {
}

class Experimentcore {
}

@enduml
